    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "Provider score comparison is inverted in _compareByScoreAndTime. The comparison returns -1 when a._score < b._score, causing LOWER-scored providers to sort first, which is backwards. Higher-scored providers should come first to be used with higher priority. This breaks provider ordering for completions, hover, diagnostics, and other language features.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -193,9 +193,9 @@ export class LanguageFeatureRegistry<T> {

 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
 		if (a._score < b._score) {
-			return -1;
-		} else if (a._score > b._score) {
 			return 1;
+		} else if (a._score > b._score) {
+			return -1;
 		}

 		// De-prioritize built-in providers
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 92,
    "severity": "high",
    "description": "Multiline regex detection is incomplete in isMultilineRegexSource. The function now only checks for CharCode.n and CharCode.r (newline and carriage return) but previously also checked for CharCode.W. Removing this check means certain multiline patterns will not be detected correctly, potentially causing single-line search logic to be used on multiline patterns, breaking search across line boundaries.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -89,7 +89,7 @@ export function isMultilineRegexSource(searchString: string): boolean {
 			}

 			const nextChCode = searchString.charCodeAt(i);
-			if (nextChCode === CharCode.n || nextChCode === CharCode.r) {
+			if (nextChCode === CharCode.n || nextChCode === CharCode.r || nextChCode === CharCode.W) {
 				return true;
 			}
 		}
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 490,
    "severity": "critical",
    "description": "Whole-word boundary validation logic is inverted in isValidMatch. For a valid whole-word match, BOTH the left AND right boundaries must be word boundaries (so the match is surrounded by non-word characters). The code uses OR (`||`) instead of AND (`&&`), allowing matches that have a boundary on only one side. This breaks whole-word search, causing incorrect matches to be highlighted and selected.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -487,7 +487,7 @@ function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: strin
 export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
 	return (
 		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
 	);
 }
"
  }
]

